 82Ôćĺ            .unbox();
 83Ôćĺ        let [hn0, hn1, hn2, hn3, hn4, hn5, hn6, hn7] = hint_ntt_iter
 84Ôćĺ            .multi_pop_front::<8>()
 85Ôćĺ            .unwrap()
 86Ôćĺ            .unbox();
