186Ôćĺ/// Horner-encode up to 9 Zq values into a u128.
187Ôćĺ/// Encoding: v0 + Q*(v1 + Q*(v2 + ... + Q*v8))
188Ôćĺfn pack_9(vals: Span<Zq>) -> u128 {
189Ôćĺ    let n = vals.len();
190Ôćĺ    match n {
191Ôćĺ        0 => 0_u128,
192Ôćĺ        1 => {
193Ôćĺ            let a: Zq = v(vals, 0);
194Ôćĺ            upcast(a)
195Ôćĺ        },
196Ôćĺ        2 => {
197Ôćĺ            let a1: Acc1 = add(v(vals, 0), mul(Q_CONST, v(vals, 1)));
198Ôćĺ            upcast(a1)
199Ôćĺ        },
200Ôćĺ        3 => {
201Ôćĺ            let a1: Acc1 = add(v(vals, 1), mul(Q_CONST, v(vals, 2)));
202Ôćĺ            let a2: Acc2 = add(v(vals, 0), mul(Q_CONST, a1));
203Ôćĺ            upcast(a2)
204Ôćĺ        },
205Ôćĺ        4 => {
206Ôćĺ            let a1: Acc1 = add(v(vals, 2), mul(Q_CONST, v(vals, 3)));
207Ôćĺ            let a2: Acc2 = add(v(vals, 1), mul(Q_CONST, a1));
208Ôćĺ            let a3: Acc3 = add(v(vals, 0), mul(Q_CONST, a2));
209Ôćĺ            upcast(a3)
210Ôćĺ        },
211Ôćĺ        5 => {
212Ôćĺ            let a1: Acc1 = add(v(vals, 3), mul(Q_CONST, v(vals, 4)));
213Ôćĺ            let a2: Acc2 = add(v(vals, 2), mul(Q_CONST, a1));
214Ôćĺ            let a3: Acc3 = add(v(vals, 1), mul(Q_CONST, a2));
215Ôćĺ            let a4: Acc4 = add(v(vals, 0), mul(Q_CONST, a3));
216Ôćĺ            upcast(a4)
217Ôćĺ        },
218Ôćĺ        6 => {
219Ôćĺ            let a1: Acc1 = add(v(vals, 4), mul(Q_CONST, v(vals, 5)));
220Ôćĺ            let a2: Acc2 = add(v(vals, 3), mul(Q_CONST, a1));
221Ôćĺ            let a3: Acc3 = add(v(vals, 2), mul(Q_CONST, a2));
222Ôćĺ            let a4: Acc4 = add(v(vals, 1), mul(Q_CONST, a3));
223Ôćĺ            let a5: Acc5 = add(v(vals, 0), mul(Q_CONST, a4));
224Ôćĺ            upcast(a5)
225Ôćĺ        },
226Ôćĺ        7 => {
227Ôćĺ            let a1: Acc1 = add(v(vals, 5), mul(Q_CONST, v(vals, 6)));
228Ôćĺ            let a2: Acc2 = add(v(vals, 4), mul(Q_CONST, a1));
229Ôćĺ            let a3: Acc3 = add(v(vals, 3), mul(Q_CONST, a2));
230Ôćĺ            let a4: Acc4 = add(v(vals, 2), mul(Q_CONST, a3));
231Ôćĺ            let a5: Acc5 = add(v(vals, 1), mul(Q_CONST, a4));
232Ôćĺ            let a6: Acc6 = add(v(vals, 0), mul(Q_CONST, a5));
233Ôćĺ            upcast(a6)
234Ôćĺ        },
235Ôćĺ        8 => {
236Ôćĺ            let a1: Acc1 = add(v(vals, 6), mul(Q_CONST, v(vals, 7)));
237Ôćĺ            let a2: Acc2 = add(v(vals, 5), mul(Q_CONST, a1));
238Ôćĺ            let a3: Acc3 = add(v(vals, 4), mul(Q_CONST, a2));
239Ôćĺ            let a4: Acc4 = add(v(vals, 3), mul(Q_CONST, a3));
240Ôćĺ            let a5: Acc5 = add(v(vals, 2), mul(Q_CONST, a4));
241Ôćĺ            let a6: Acc6 = add(v(vals, 1), mul(Q_CONST, a5));
242Ôćĺ            let a7: Acc7 = add(v(vals, 0), mul(Q_CONST, a6));
243Ôćĺ            upcast(a7)
244Ôćĺ        },
245Ôćĺ        9 => {
246Ôćĺ            let a1: Acc1 = add(v(vals, 7), mul(Q_CONST, v(vals, 8)));
247Ôćĺ            let a2: Acc2 = add(v(vals, 6), mul(Q_CONST, a1));
248Ôćĺ            let a3: Acc3 = add(v(vals, 5), mul(Q_CONST, a2));
249Ôćĺ            let a4: Acc4 = add(v(vals, 4), mul(Q_CONST, a3));
250Ôćĺ            let a5: Acc5 = add(v(vals, 3), mul(Q_CONST, a4));
251Ôćĺ            let a6: Acc6 = add(v(vals, 2), mul(Q_CONST, a5));
252Ôćĺ            let a7: Acc7 = add(v(vals, 1), mul(Q_CONST, a6));
253Ôćĺ            let a8: Acc8 = add(v(vals, 0), mul(Q_CONST, a7));
254Ôćĺ            upcast(a8)
255Ôćĺ        },
256Ôćĺ        _ => core::panic_with_felt252('pack_9: count > 9'),
257Ôćĺ    }
258Ôćĺ}
