260Ôćĺ/// Unpack a u128 into `count` Zq values using iterated DivRem by Q.
261Ôćĺfn unpack_9(packed: u128, count: usize, ref output: Array<Zq>) {
262Ôćĺ    if count == 0 {
263Ôćĺ        return;
264Ôćĺ    }
265Ôćĺ    let acc8: Acc8 = downcast(packed).expect('invalid packed value');
266Ôćĺ    let (acc7, r0) = bounded_int_div_rem(acc8, NZ_Q);
267Ôćĺ    output.append(r0);
268Ôćĺ    if count == 1 {
269Ôćĺ        return;
270Ôćĺ    }
271Ôćĺ    let (acc6, r1) = bounded_int_div_rem(acc7, NZ_Q);
272Ôćĺ    output.append(r1);
273Ôćĺ    if count == 2 {
274Ôćĺ        return;
275Ôćĺ    }
276Ôćĺ    let (acc5, r2) = bounded_int_div_rem(acc6, NZ_Q);
277Ôćĺ    output.append(r2);
278Ôćĺ    if count == 3 {
279Ôćĺ        return;
280Ôćĺ    }
281Ôćĺ    let (acc4, r3) = bounded_int_div_rem(acc5, NZ_Q);
282Ôćĺ    output.append(r3);
283Ôćĺ    if count == 4 {
284Ôćĺ        return;
285Ôćĺ    }
286Ôćĺ    let (acc3, r4) = bounded_int_div_rem(acc4, NZ_Q);
287Ôćĺ    output.append(r4);
288Ôćĺ    if count == 5 {
289Ôćĺ        return;
290Ôćĺ    }
291Ôćĺ    let (acc2, r5) = bounded_int_div_rem(acc3, NZ_Q);
292Ôćĺ    output.append(r5);
293Ôćĺ    if count == 6 {
294Ôćĺ        return;
295Ôćĺ    }
296Ôćĺ    let (acc1, r6) = bounded_int_div_rem(acc2, NZ_Q);
297Ôćĺ    output.append(r6);
298Ôćĺ    if count == 7 {
299Ôćĺ        return;
300Ôćĺ    }
301Ôćĺ    let (acc0, r7) = bounded_int_div_rem(acc1, NZ_Q);
302Ôćĺ    output.append(r7);
303Ôćĺ    if count == 8 {
304Ôćĺ        return;
305Ôćĺ    }
306Ôćĺ    output.append(acc0);
307Ôćĺ}
