309Ôćĺ/// Unpack a u128 into exactly 9 Zq values. No count checks.
310Ôćĺfn unpack_9_full(packed: u128, ref output: Array<Zq>) {
311Ôćĺ    let acc8: Acc8 = downcast(packed).expect('bad pack');
312Ôćĺ    let (acc7, r0) = bounded_int_div_rem(acc8, NZ_Q);
313Ôćĺ    output.append(r0);
314Ôćĺ    let (acc6, r1) = bounded_int_div_rem(acc7, NZ_Q);
315Ôćĺ    output.append(r1);
316Ôćĺ    let (acc5, r2) = bounded_int_div_rem(acc6, NZ_Q);
317Ôćĺ    output.append(r2);
318Ôćĺ    let (acc4, r3) = bounded_int_div_rem(acc5, NZ_Q);
319Ôćĺ    output.append(r3);
320Ôćĺ    let (acc3, r4) = bounded_int_div_rem(acc4, NZ_Q);
321Ôćĺ    output.append(r4);
322Ôćĺ    let (acc2, r5) = bounded_int_div_rem(acc3, NZ_Q);
323Ôćĺ    output.append(r5);
324Ôćĺ    let (acc1, r6) = bounded_int_div_rem(acc2, NZ_Q);
325Ôćĺ    output.append(r6);
326Ôćĺ    let (acc0, r7) = bounded_int_div_rem(acc1, NZ_Q);
327Ôćĺ    output.append(r7);
328Ôćĺ    output.append(acc0);
329Ôćĺ}
