336Ôćĺ    let (acc5, r1) = bounded_int_div_rem(acc6, NZ_Q);
337Ôćĺ    output.append(r1);
338Ôćĺ    let (acc4, r2) = bounded_int_div_rem(acc5, NZ_Q);
339Ôćĺ    output.append(r2);
340Ôćĺ    let (acc3, r3) = bounded_int_div_rem(acc4, NZ_Q);
