351Ôćĺ/// Pack 512 Zq values into 29 felt252 slots.
352Ôćĺ/// Each slot encodes up to 18 values: pack_9(lo) + pack_9(hi) * 2^128.
353Ôćĺpub fn pack_public_key(values: Span<Zq>) -> Array<felt252> {
354Ôćĺ    assert!(values.len() == 512, "expected 512 values");
355Ôćĺ    let mut result: Array<felt252> = array![];
356Ôćĺ    let mut offset: usize = 0;
357Ôćĺ    // 28 full slots: 9 lo + 9 hi = 18 values each (504 total)
358Ôćĺ    while offset != 504 {
359Ôćĺ        let lo_felt: felt252 = pack_9(values.slice(offset, 9)).into();
360Ôćĺ        let hi_felt: felt252 = pack_9(values.slice(offset + 9, 9)).into();
361Ôćĺ        result.append(lo_felt + hi_felt * TWO_POW_128);
362Ôćĺ        offset += 18;
363Ôćĺ    }
364Ôćĺ    // Last slot: 8 remaining values in low half only
365Ôćĺ    result.append(pack_9(values.slice(504, 8)).into());
366Ôćĺ    result
367Ôćĺ}
368Ôćĺ
369Ôćĺ/// Unpack 29 felt252 slots back to 512 Zq values.
370Ôćĺpub fn unpack_public_key(packed: Span<felt252>) -> Array<Zq> {
371Ôćĺ    let mut output: Array<Zq> = array![];
372Ôćĺ    let mut packed = packed;
373Ôćĺ    // 28 full slots: 9 lo + 9 hi = 18 values each (504 total)
374Ôćĺ    let mut i: usize = 0;
375Ôćĺ    while i != 28 {
376Ôćĺ        let val_u256: u256 = (*packed.pop_front().unwrap()).into();
377Ôćĺ        unpack_9_full(val_u256.low, ref output);
378Ôćĺ        unpack_9_full(val_u256.high, ref output);
379Ôćĺ        i += 1;
380Ôćĺ    }
381Ôćĺ    // Last slot: 8 remaining values in low half
382Ôćĺ    let val_u256: u256 = (*packed.pop_front().unwrap()).into();
383Ôćĺ    unpack_8(val_u256.low, ref output);
384Ôćĺ    output
385Ôćĺ}
