135Ôćĺ        fn validate_transaction(self: @ComponentState<TContractState>) -> felt252 {
136Ôćĺ            let tx_info = starknet::get_tx_info().unbox();
137Ôćĺ            let tx_hash = tx_info.transaction_hash;
138Ôćĺ            let signature = tx_info.signature;
139Ôćĺ            assert(self._is_valid_signature(tx_hash, signature), Errors::INVALID_SIGNATURE);
