143Ôćĺ        /// Returns whether the given signature is valid for the given hash.
144Ôćĺ        fn _is_valid_signature(
145Ôćĺ            self: @ComponentState<TContractState>, hash: felt252, signature: Span<felt252>,
146Ôćĺ        ) -> bool {
147Ôćĺ            let mut sig_span = signature;
148Ôćĺ            let sig: PackedFalconSignatureWithHint = match Serde::deserialize(ref sig_span) {
149Ôćĺ                Option::Some(s) => s,
