14Ôćĺ    if tx_version >= QUERY_OFFSET {
15Ôćĺ        QUERY_OFFSET + MIN_TRANSACTION_VERSION <= tx_version
16Ôćĺ    } else {
17Ôćĺ        MIN_TRANSACTION_VERSION <= tx_version
18Ôćĺ    }
19Ôćĺ}
