  1Ôćĺ# Effect + Next.js Integration
  2Ôćĺ
  3Ôćĺ`@prb/effect-next` provides typed helpers for integrating Effect with Next.js 15+ App RouterÔÇöroute handlers, server
  4Ôćĺactions, middleware, and React hooks.
  5Ôćĺ
  6Ôćĺ## Core API
  7Ôćĺ
  8Ôćĺ### Route Handlers
  9Ôćĺ
 10Ôćĺ```typescript
 11Ôćĺ// app/api/users/[id]/route.ts
 12Ôćĺimport { effectHandler } from "@prb/effect-next/handlers";
 13Ôćĺimport { Effect } from "effect";
 14Ôćĺimport { RouteParams } from "@prb/effect-next/params";
 15Ôćĺ
 16Ôćĺexport const GET = effectHandler(
 17Ôćĺ  Effect.gen(function* () {
 18Ôćĺ    const params = yield* RouteParams;
 19Ôćĺ    const user = yield* fetchUser(params.id);
 20Ôćĺ    return Response.json(user);
 21Ôćĺ  }),
 22Ôćĺ  AppLayer
 23Ôćĺ);
 24Ôćĺ```
 25Ôćĺ
 26Ôćĺ### Server Actions
 27Ôćĺ
 28Ôćĺ```typescript
 29Ôćĺ"use server";
 30Ôćĺimport { effectAction } from "@prb/effect-next/action";
 31Ôćĺimport { Effect } from "effect";
 32Ôćĺ
 33Ôćĺexport const createUser = effectAction(
 34Ôćĺ  Effect.gen(function* () {
 35Ôćĺ    const db = yield* Database;
 36Ôćĺ    return yield* db.insert(users).values({ name: "Alice" });
 37Ôćĺ  }),
 38Ôćĺ  AppLayer
 39Ôćĺ);
 40Ôćĺ
 41Ôćĺ// Returns Exit-like result with _tag: "Success" | "Failure"
 42Ôćĺconst result = await createUser();
 43Ôćĺif (result._tag === "Success") {
 44Ôćĺ  console.log(result.value);
 45Ôćĺ}
 46Ôćĺ```
 47Ôćĺ
 48Ôćĺ### Middleware
 49Ôćĺ
 50Ôćĺ```typescript
 51Ôćĺ// middleware.ts
 52Ôćĺimport { effectMiddleware } from "@prb/effect-next/middleware";
 53Ôćĺimport { Effect, Layer } from "effect";
 54Ôćĺimport { Headers } from "@prb/effect-next/headers";
 55Ôćĺ
 56Ôćĺconst AuthLayer = Layer.effect(
 57Ôćĺ  AuthService,
 58Ôćĺ  Effect.gen(function* () {
 59Ôćĺ    const headers = yield* Headers;
 60Ôćĺ    const token = headers.get("authorization");
 61Ôćĺ    if (!token) yield* Effect.fail({ _tag: "Unauthorized" });
 62Ôćĺ    return { validateToken: () => Effect.succeed(true) };
 63Ôćĺ  })
 64Ôćĺ);
 65Ôćĺ
 66Ôćĺexport const middleware = effectMiddleware(
 67Ôćĺ  Effect.gen(function* () {
 68Ôćĺ    yield* AuthService;
 69Ôćĺ    return NextResponse.next();
 70Ôćĺ  }),
 71Ôćĺ  AuthLayer
 72Ôćĺ);
 73Ôćĺ```
 74Ôćĺ
 75Ôćĺ## React Hooks
 76Ôćĺ
 77ÔćĺClient-side hooks for running Effects in React components.
 78Ôćĺ
 79Ôćĺ```typescript
 80Ôćĺ"use client";
 81Ôćĺimport {
 82Ôćĺ  EffectNextProvider,
 83Ôćĺ  useEffectNextRuntime,
 84Ôćĺ  useEffectMemo,
 85Ôćĺ  useEffectOnce,
 86Ôćĺ  useForkEffect,
 87Ôćĺ  useStream,
 88Ôćĺ  useStreamLatest,
 89Ôćĺ  useSubscriptionRef
 90Ôćĺ} from "@prb/effect-next/react-hooks";
 91Ôćĺ
 92Ôćĺ// Wrap app with provider
 93Ôćĺ<EffectNextProvider runtime={runtime}>{children}</EffectNextProvider>;
 94Ôćĺ
 95Ôćĺ// Access runtime
 96Ôćĺconst runtime = useEffectNextRuntime();
 97Ôćĺ
 98Ôćĺ// Run Effect with dependencies (like useMemo)
 99Ôćĺconst data = useEffectMemo(() => effect, [deps], runtime);
100Ôćĺ
101Ôćĺ// Run Effect once on mount
102Ôćĺconst data = useEffectOnce(effect, runtime);
103Ôćĺ
104Ôćĺ// Run Effect in background (fire-and-forget)
105ÔćĺuseForkEffect(effect, runtime, [deps]);
106Ôćĺ
107Ôćĺ// Subscribe to Stream
108Ôćĺconst values = useStream(stream, runtime);
109Ôćĺconst latest = useStreamLatest(stream, runtime, initialValue);
110Ôćĺ
111Ôćĺ// Subscribe to SubscriptionRef
112Ôćĺconst value = useSubscriptionRef(ref, runtime);
113Ôćĺ```
114Ôćĺ
115Ôćĺ## Request-Scoped Cache
116Ôćĺ
117ÔćĺLeverage React's `cache()` for request deduplication.
118Ôćĺ
119Ôćĺ```typescript
120Ôćĺimport { reactCache, reactCacheFn, reactCacheWithKey } from "@prb/effect-next/cache";
121Ôćĺimport { ManagedRuntime } from "effect";
122Ôćĺ
123Ôćĺconst runtime = ManagedRuntime.make(AppLayer);
124Ôćĺ
125Ôćĺ// Cache an Effect
126Ôćĺexport const getUsers = reactCache(
127Ôćĺ  Effect.gen(function* () {
128Ôćĺ    const db = yield* Database;
129Ôćĺ    return yield* db.query("SELECT * FROM users");
130Ôćĺ  }),
131Ôćĺ  runtime
132Ôćĺ);
133Ôćĺ
134Ôćĺ// Cache a function with arguments
135Ôćĺexport const getUserById = reactCacheFn((id: string) =>
136Ôćĺ  Effect.gen(function* () {
137Ôćĺ    const db = yield* Database;
138Ôćĺ    return yield* db.query(`SELECT * FROM users WHERE id = ${id}`);
139Ôćĺ  }),
140Ôćĺ  runtime
141Ôćĺ);
142Ôćĺ
143Ôćĺ// Cache with custom key
144Ôćĺexport const getUser = reactCacheWithKey(
145Ôćĺ  (opts) => fetchUserEffect(opts),
146Ôćĺ  (opts) => `user:${opts.id}`,
147Ôćĺ  runtime
148Ôćĺ);
149Ôćĺ```
150Ôćĺ
151Ôćĺ## Headers & Cookies
152Ôćĺ
153Ôćĺ```typescript
154Ôćĺimport { Headers, Cookies } from "@prb/effect-next/headers";
155Ôćĺ
156ÔćĺEffect.gen(function* () {
157Ôćĺ  const headers = yield* Headers;
158Ôćĺ  const userAgent = headers.get("user-agent");
159Ôćĺ
160Ôćĺ  const cookies = yield* Cookies;
161Ôćĺ  const sessionId = cookies.get("sessionId");
162Ôćĺ});
163Ôćĺ```
164Ôćĺ
165Ôćĺ## Params
166Ôćĺ
167Ôćĺ```typescript
168Ôćĺimport { RouteParams, SearchParams } from "@prb/effect-next/params";
169Ôćĺ
170ÔćĺEffect.gen(function* () {
171Ôćĺ  const params = yield* RouteParams;
172Ôćĺ  const userId = params.id;
173Ôćĺ
174Ôćĺ  const searchParams = yield* SearchParams;
175Ôćĺ  const page = searchParams.page;
176Ôćĺ});
177Ôćĺ```
178Ôćĺ
179Ôćĺ## Navigation
180Ôćĺ
181Ôćĺ```typescript
182Ôćĺimport { redirect, rewrite, notFound } from "@prb/effect-next/navigation";
183Ôćĺ
184ÔćĺEffect.gen(function* () {
185Ôćĺ  yield* redirect("/login");
186Ôćĺ  yield* rewrite("/new-path");
187Ôćĺ  yield* notFound();
188Ôćĺ});
189Ôćĺ```
190Ôćĺ
191Ôćĺ## Testing Kit
192Ôćĺ
193Ôćĺ```typescript
194Ôćĺimport {
195Ôćĺ  assertRight,
196Ôćĺ  assertLeft,
197Ôćĺ  expectTaggedFailure,
198Ôćĺ  expectDefect,
199Ôćĺ  runExpectSuccess,
200Ôćĺ  runExpectFailure,
201Ôćĺ  makeMockRuntime
202Ôćĺ} from "@prb/effect-next/testing-kit";
203Ôćĺ
204Ôćĺ// Assert success
205Ôćĺtest("should succeed", async () => {
206Ôćĺ  const exit = await Effect.runPromiseExit(effect);
207Ôćĺ  const value = assertRight(exit);
208Ôćĺ  expect(value).toBe(42);
209Ôćĺ});
210Ôćĺ
211Ôćĺ// Assert specific failure tag
212Ôćĺtest("should fail with NotFound", async () => {
213Ôćĺ  const exit = await Effect.runPromiseExit(effect);
214Ôćĺ  expectTaggedFailure(exit, "NotFound");
215Ôćĺ});
216Ôćĺ
217Ôćĺ// Run and expect success
218Ôćĺtest("should create user", async () => {
219Ôćĺ  const user = await runExpectSuccess(createUser(), runtime);
220Ôćĺ  expect(user.name).toBe("Alice");
221Ôćĺ});
222Ôćĺ```
223Ôćĺ
224Ôćĺ## Best Practices
225Ôćĺ
226Ôćĺ1. **Use `Effect.fn()`** ÔÇö Automatic telemetry spans and better stack traces
227Ôćĺ2. **Centralize layers** ÔÇö Create `AppLayer` with all shared services
228Ôćĺ3. **Error handling** ÔÇö Use `.catchAll()` or `.catchTag()` for Effect-level errors
229Ôćĺ4. **Request caching** ÔÇö Use `reactCache` for request-scoped memoization
230Ôćĺ5. **Server-only Effect** ÔÇö Effect-ts shines server-side; avoid complex Effect in client components
231Ôćĺ

