 56Ôćĺfunction colorStatus(status: string): string {
 57Ôćĺ	switch (status) {
 58Ôćĺ		case "running":
 59Ôćĺ		case "waiting-approval":
 60Ôćĺ			return yellow(status);
 61Ôćĺ		case "done":
 62Ôćĺ		case "completed":
 63Ôćĺ			return green(status);
 64Ôćĺ		case "cancelled":
 65Ôćĺ			return dim(status);
 66Ôćĺ		case "failed":
 67Ôćĺ		case "error":
 68Ôćĺ			return red(status);
 69Ôćĺ		default:
 70Ôćĺ			return dim(status);
 71Ôćĺ	}
 72Ôćĺ}
