 74Ôćĺfunction relativeTime(ms: number | null): string {
 75Ôćĺ	if (!ms) return dim("ÔÇö");
 76Ôćĺ	const diff = Date.now() - ms;
 77Ôćĺ	const mins = Math.floor(diff / 60_000);
 78Ôćĺ	if (mins < 1) return "just now";
 79Ôćĺ	if (mins < 60) return `${mins}m ago`;
 80Ôćĺ	const hrs = Math.floor(mins / 60);
 81Ôćĺ	if (hrs < 24) return `${hrs}h ago`;
 82Ôćĺ	return `${Math.floor(hrs / 24)}d ago`;
 83Ôćĺ}
