203Ôćĺasync function runMenu(runs: RunRow[], cli: string): Promise<void> {
204Ôćĺ	printHeader();
205Ôćĺ	if (runs.length === 0) {
206Ôćĺ		console.log(dim("  No previous runs found.\n"));
207Ôćĺ		console.log(`  ${bold("n")}  Start a new run`);
208Ôćĺ		console.log(`  ${bold("q")}  Quit\n`);
209Ôćĺ		const ans = await ask("  Select [n/q]: ");
210Ôćĺ		if (ans === "n") return runNew(cli);
211Ôćĺ		process.exit(0);
212Ôćĺ	}
213Ôćĺ	console.log(`  ${bold("Existing runs:")}\n`);
214Ôćĺ	printRunTable(runs);
215Ôćĺ	console.log(`\n  ${bold("n")}  Start a new run    ${bold("q")}  Quit\n`);
216Ôćĺ	const ans = await ask(`  Select a run [1ÔÇô${runs.length} / n / q]: `);
217Ôćĺ	if (ans === "q") process.exit(0);
218Ôćĺ	if (ans === "n") return runNew(cli);
219Ôćĺ	const idx = parseInt(ans, 10);
220Ôćĺ	if (Number.isNaN(idx) || idx < 1 || idx > runs.length) {
221Ôćĺ		console.log(red("\n  Invalid selection.\n"));
222Ôćĺ		await Bun.sleep(800);
223Ôćĺ		return runMenu(runs, cli);
224Ôćĺ	}
225Ôćĺ	return actionMenu(runs[idx - 1]!, cli);
226Ôćĺ}
