228Ôćĺasync function actionMenu(run: RunRow, cli: string): Promise<void> {
229Ôćĺ	printHeader();
230Ôćĺ	console.log(`  Run   ${cyan(run.run_id)}`);
231Ôćĺ	console.log(`  Status  ${colorStatus(run.status)}    ${dim(relativeTime(run.started_at_ms ?? run.created_at_ms))}\n`);
232Ôćĺ	const isActive = run.status === "running" || run.status === "waiting-approval";
233Ôćĺ	const opts: Array<{ key: string; label: string }> = [];
234Ôćĺ	opts.push({ key: "r", label: "Resume this run" });
235Ôćĺ	if (isActive) opts.push({ key: "c", label: "Cancel this run" });
236Ôćĺ	opts.push({ key: "d", label: red("Delete this run") });
237Ôćĺ	opts.push({ key: "b", label: "Back" });
238Ôćĺ	for (const o of opts) console.log(`  ${bold(o.key)}  ${o.label}`);
239Ôćĺ	const ans = await ask(`\n  Action [${opts.map((o) => o.key).join("/")}]: `);
240Ôćĺ	if (ans === "b") return runMenu(listRuns(), cli);
241Ôćĺ	if (ans === "r") return runResume(cli, run.run_id);
242Ôćĺ	if (ans === "c" && isActive) {
243Ôćĺ		if ((await ask(`  ${yellow("Cancel")} ${cyan(run.run_id)}? [y/N]: `)).toLowerCase() === "y") {
244Ôćĺ			await runCancel(cli, run.run_id);
245Ôćĺ			await Bun.sleep(600);
246Ôćĺ			return runMenu(listRuns(), cli);
247Ôćĺ		}
248Ôćĺ		return actionMenu(run, cli);
249Ôćĺ	}
250Ôćĺ	if (ans === "d") {
251Ôćĺ		if ((await ask(`  ${red("Permanently delete")} ${cyan(run.run_id)}? [y/N]: `)).toLowerCase() === "y") {
252Ôćĺ			deleteRun(run.run_id);
253Ôćĺ			console.log(green(`\n  Deleted ${run.run_id}.`));
254Ôćĺ			await Bun.sleep(600);
255Ôćĺ			return runMenu(listRuns(), cli);
256Ôćĺ		}
257Ôćĺ		return actionMenu(run, cli);
258Ôćĺ	}
259Ôćĺ	console.log(red("\n  Invalid selection.\n"));
260Ôćĺ	await Bun.sleep(500);
261Ôćĺ	return actionMenu(run, cli);
262Ôćĺ}
