212Ôćĺ///
213Ôćĺ/// let (sk, vk) = Falcon::<Shake256Hash>::keygen();
214Ôćĺ/// let sig = Falcon::<Shake256Hash>::sign(&sk, b"message");
215Ôćĺ/// assert!(Falcon::<Shake256Hash>::verify(&vk, b"message", &sig).unwrap());
