223Ôćĺ    ///
224Ôćĺ    /// Creates a fresh Falcon-512 keypair using the system's cryptographically
225Ôćĺ    /// secure random number generator.
226Ôćĺ    ///
227Ôćĺ    /// # Returns
228Ôćĺ    ///
229Ôćĺ    /// A tuple of (secret key, verifying key).
230Ôćĺ    ///
231Ôćĺ    /// # Panics
232Ôćĺ    ///
233Ôćĺ    /// Panics if the system RNG fails to provide random bytes.
234Ôćĺ    #[cfg(feature = "shake")]
235Ôćĺ    pub fn keygen() -> (SecretKey, VerifyingKey) {
236Ôćĺ        use getrandom::getrandom;
237Ôćĺ        let mut seed = [0u8; 32];
