239Ôćĺ        Self::keygen_with_seed(&seed)
240Ôćĺ    }
241Ôćĺ
242Ôćĺ    /// Generate a new keypair with a provided seed.
243Ôćĺ    ///
244Ôćĺ    /// Creates a deterministic Falcon-512 keypair from the given seed.
245Ôćĺ    /// The same seed will always produce the same keypair, which is
246Ôćĺ    /// useful for testing and key recovery.
247Ôćĺ    ///
248Ôćĺ    /// # Arguments
249Ôćĺ    ///
250Ôćĺ    /// * `seed` - A seed slice (up to 56 bytes used; shorter seeds are zero-padded)
251Ôćĺ    ///
252Ôćĺ    /// # Returns
253Ôćĺ    ///
254Ôćĺ    /// A tuple of (secret key, verifying key).
255Ôćĺ    pub fn keygen_with_seed(seed: &[u8]) -> (SecretKey, VerifyingKey) {
256Ôćĺ        // Create a deterministic RNG from the seed
257Ôćĺ        let mut full_seed = [0u8; SEED_LEN];
258Ôćĺ        let copy_len = seed.len().min(SEED_LEN);
259Ôćĺ        full_seed[..copy_len].copy_from_slice(&seed[..copy_len]);
260Ôćĺ        let mut rng = ChaCha20::new(&full_seed);
261Ôćĺ        let mut random_bytes = |n: usize| rng.random_bytes(n);
262Ôćĺ
263Ôćĺ        Self::keygen_with_rng(&mut random_bytes)
264Ôćĺ    }
265Ôćĺ
266Ôćĺ    /// Generate a new keypair with a provided random byte source.
267Ôćĺ    ///
268Ôćĺ    /// Creates a Falcon-512 keypair using a custom source of randomness.
269Ôćĺ    /// This is the most flexible key generation method, useful for
270Ôćĺ    /// deterministic testing or custom RNG implementations.
271Ôćĺ    ///
272Ôćĺ    /// # Arguments
273Ôćĺ    ///
274Ôćĺ    /// * `random_bytes` - A closure that returns `n` random bytes when called
275Ôćĺ    ///
276Ôćĺ    /// # Returns
277Ôćĺ    ///
278Ôćĺ    /// A tuple of (secret key, verifying key).
279Ôćĺ    pub fn keygen_with_rng<F: FnMut(usize) -> Vec<u8>>(
280Ôćĺ        random_bytes: &mut F,
281Ôćĺ    ) -> (SecretKey, VerifyingKey) {
282Ôćĺ        // Generate NTRU polynomials
283Ôćĺ        let (f, g, capital_f, capital_g) = ntru_gen(random_bytes);
284Ôćĺ
285Ôćĺ        // Compute public key h = g/f mod (x^n + 1, q)
286Ôćĺ        let f_vec: Vec<i32> = f.iter().copied().collect();
287Ôćĺ        let g_vec: Vec<i32> = g.iter().copied().collect();
288Ôćĺ        let h_vec = div_zq(&g_vec, &f_vec).expect("f should be invertible");
289Ôćĺ        let mut h = [0i32; N];
290Ôćĺ        h.copy_from_slice(&h_vec);
291Ôćĺ
292Ôćĺ        // Compute basis B0 = [[g, -f], [G, -F]] in coefficient representation
293Ôćĺ        // Note: Use regular negation, NOT modular negation (neg_zq), for the Gram matrix
294Ôćĺ        let neg_f: Vec<f64> = f_vec.iter().map(|&x| -(x as f64)).collect();
295Ôćĺ        let neg_f_cap: Vec<f64> = capital_f.iter().map(|&x| -(x as f64)).collect();
296Ôćĺ
297Ôćĺ        // B0 in coefficient representation (f64 for Gram computation)
298Ôćĺ        let b0: [[Vec<f64>; 2]; 2] = [
299Ôćĺ            [g_vec.iter().map(|&x| x as f64).collect(), neg_f],
300Ôćĺ            [capital_g.iter().map(|&x| x as f64).collect(), neg_f_cap],
301Ôćĺ        ];
302Ôćĺ
303Ôćĺ        // Convert B0 to FFT representation (for use in signing)
304Ôćĺ        let b0_fft = [
305Ôćĺ            [fft(&b0[0][0]), fft(&b0[0][1])],
306Ôćĺ            [fft(&b0[1][0]), fft(&b0[1][1])],
307Ôćĺ        ];
308Ôćĺ
309Ôćĺ        // Compute Gram matrix G0 = B0 * B0^* in coefficient representation
310Ôćĺ        // (matching Python's approach: gram() in coef domain, then FFT)
311Ôćĺ        let g0 = gram(&b0);
312Ôćĺ        let g0_fft = [
313Ôćĺ            [fft(&g0[0][0]), fft(&g0[0][1])],
314Ôćĺ            [fft(&g0[1][0]), fft(&g0[1][1])],
315Ôćĺ        ];
316Ôćĺ
317Ôćĺ        // Build ffLDL tree
318Ôćĺ        let mut tree = ffldl_fft(&g0_fft);
319Ôćĺ        normalize_tree(&mut tree, SIGMA);
320Ôćĺ
321Ôćĺ        let sk = SecretKey {
322Ôćĺ            f,
323Ôćĺ            g,
324Ôćĺ            capital_f,
325Ôćĺ            capital_g,
326Ôćĺ            b0_fft,
327Ôćĺ            tree,
328Ôćĺ        };
329Ôćĺ
330Ôćĺ        let vk = VerifyingKey { h };
331Ôćĺ
332Ôćĺ        (sk, vk)
333Ôćĺ    }
