366Ôćĺ    /// Sign a message with a provided salt.
367Ôćĺ    ///
368Ôćĺ    /// Creates a Falcon-512 signature using a deterministic salt.
369Ôćĺ    /// This is useful for testing or when reproducible signatures are needed.
370Ôćĺ    ///
371Ôćĺ    /// # Arguments
372Ôćĺ    ///
373Ôćĺ    /// * `sk` - The secret key to sign with
374Ôćĺ    /// * `message` - The message bytes to sign
375Ôćĺ    /// * `salt` - A 40-byte salt value
376Ôćĺ    ///
377Ôćĺ    /// # Returns
378Ôćĺ    ///
379Ôćĺ    /// A signature that can be verified with the corresponding verifying key.
380Ôćĺ    ///
381Ôćĺ    /// # Note
382Ôćĺ    ///
383Ôćĺ    /// Using the same salt for different messages may leak information
384Ôćĺ    /// about the secret key. In production, prefer [`sign`](Self::sign).
385Ôćĺ    pub fn sign_with_salt(sk: &SecretKey, message: &[u8], salt: &[u8; SALT_LEN]) -> Signature
386Ôćĺ    where
387Ôćĺ        H: HashToPoint<Input = u8>,
388Ôćĺ    {
389Ôćĺ        let hashed = H::hash_to_point(message, salt);
390Ôćĺ        let hashed_i32: Vec<i32> = hashed.iter().map(|&x| x as i32).collect();
391Ôćĺ
392Ôćĺ        // Initialize seed from salt (seed persists across iterations)
393Ôćĺ        let mut seed = [0u8; SEED_LEN];
394Ôćĺ        seed[..SALT_LEN].copy_from_slice(salt);
395Ôćĺ
396Ôćĺ        // Signing loop - repeat until we find a short enough signature
397Ôćĺ        loop {
398Ôćĺ            let mut rng = ChaCha20::new(&seed);
399Ôćĺ            let mut random_bytes = |n: usize| rng.random_bytes(n);
400Ôćĺ
401Ôćĺ            // Sample preimage
402Ôćĺ            let (s0, s1) = Self::sample_preimage(sk, &hashed_i32, &mut random_bytes);
403Ôćĺ
404Ôćĺ            // Check Euclidean norm
405Ôćĺ            let s0_slice: &[i32] = &s0;
406Ôćĺ            let s1_slice: &[i32] = &s1;
407Ôćĺ            let norm = sqnorm(&[s0_slice, s1_slice]);
408Ôćĺ
409Ôćĺ            if norm <= SIG_BOUND {
410Ôćĺ                // Try to compress s1
411Ôćĺ                let slen = SIG_BYTELEN - HEAD_LEN - SALT_LEN;
412Ôćĺ                if let Some(s1_enc) = compress(&s1, slen) {
413Ôćĺ                    return Signature {
414Ôćĺ                        header: 0x30 + LOGN,
415Ôćĺ                        salt: *salt,
416Ôćĺ                        s1_enc,
417Ôćĺ                    };
418Ôćĺ                }
419Ôćĺ            }
420Ôćĺ
421Ôćĺ            // If norm too large or compression failed, try again with different randomness
422Ôćĺ            // Advance the seed using RNG output
423Ôćĺ            seed[SALT_LEN..].copy_from_slice(&rng.random_bytes(SEED_LEN - SALT_LEN)[..]);
424Ôćĺ        }
425Ôćĺ    }
