446Ôćĺ    ) -> (Vec<i32>, Vec<i32>) {
447Ôćĺ        let hashed_i32: Vec<i32> = hash_point.iter().map(|&x| x as i32).collect();
448Ôćĺ        let mut current_seed = *seed;
449Ôćĺ
450Ôćĺ        loop {
451Ôćĺ            let mut rng = ChaCha20::new(&current_seed);
452Ôćĺ            let mut random_bytes = |n: usize| rng.random_bytes(n);
453Ôćĺ
454Ôćĺ            let (s0, s1) = Self::sample_preimage(sk, &hashed_i32, &mut random_bytes);
455Ôćĺ
456Ôćĺ            let s0_slice: &[i32] = &s0;
457Ôćĺ            let s1_slice: &[i32] = &s1;
458Ôćĺ            let norm = sqnorm(&[s0_slice, s1_slice]);
459Ôćĺ
460Ôćĺ            if norm <= SIG_BOUND {
461Ôćĺ                return (s0, s1);
462Ôćĺ            }
463Ôćĺ
464Ôćĺ            // Advance seed
465Ôćĺ            current_seed[SALT_LEN..]
466Ôćĺ                .copy_from_slice(&rng.random_bytes(SEED_LEN - SALT_LEN)[..]);
467Ôćĺ        }
468Ôćĺ    }
469Ôćĺ
470Ôćĺ    /// Sample a short preimage s such that s0 + s1*h = point.
471Ôćĺ    fn sample_preimage<F: FnMut(usize) -> Vec<u8>>(
472Ôćĺ        sk: &SecretKey,
473Ôćĺ        point: &[i32],
474Ôćĺ        random_bytes: &mut F,
475Ôćĺ    ) -> (Vec<i32>, Vec<i32>) {
476Ôćĺ        let [[a, b], [c, d]] = &sk.b0_fft;
477Ôćĺ
478Ôćĺ        // Compute t_fft = (point, 0) * B0^(-1)
479Ôćĺ        // Because the inverse of B0 has a specific form, we can optimize
480Ôćĺ        let point_fft = fft(&point.iter().map(|&x| x as f64).collect::<Vec<_>>());
481Ôćĺ        let q_f64 = Q as f64;
482Ôćĺ
483Ôćĺ        let t0_fft: Vec<Complex> = point_fft
484Ôćĺ            .iter()
485Ôćĺ            .zip(d.iter())
486Ôćĺ            .map(|(&p, &d_i)| {
487Ôćĺ                Complex::new(
488Ôćĺ                    p.re * d_i.re / q_f64 - p.im * d_i.im / q_f64,
489Ôćĺ                    p.re * d_i.im / q_f64 + p.im * d_i.re / q_f64,
490Ôćĺ                )
491Ôćĺ            })
492Ôćĺ            .collect();
493Ôćĺ
494Ôćĺ        let t1_fft: Vec<Complex> = point_fft
495Ôćĺ            .iter()
496Ôćĺ            .zip(b.iter())
497Ôćĺ            .map(|(&p, &b_i)| {
498Ôćĺ                let neg_p = Complex::new(-p.re, -p.im);
499Ôćĺ                Complex::new(
500Ôćĺ                    (neg_p.re * b_i.re - neg_p.im * b_i.im) / q_f64,
501Ôćĺ                    (neg_p.re * b_i.im + neg_p.im * b_i.re) / q_f64,
502Ôćĺ                )
503Ôćĺ            })
504Ôćĺ            .collect();
505Ôćĺ
506Ôćĺ        let t_fft = [t0_fft, t1_fft];
507Ôćĺ
508Ôćĺ        // Sample z using ffsampling
509Ôćĺ        let z_fft = ffsampling_fft(&t_fft, &sk.tree, SIGMIN, random_bytes);
510Ôćĺ
511Ôćĺ        // Compute v = z * B0
512Ôćĺ        let v0_fft = add_fft(&mul_fft(&z_fft[0], a), &mul_fft(&z_fft[1], c));
513Ôćĺ        let v1_fft = add_fft(&mul_fft(&z_fft[0], b), &mul_fft(&z_fft[1], d));
514Ôćĺ
515Ôćĺ        let v0_float = ifft(&v0_fft);
516Ôćĺ        let v1_float = ifft(&v1_fft);
517Ôćĺ
518Ôćĺ        let v0: Vec<i32> = v0_float.iter().map(|&x| x.round() as i32).collect();
519Ôćĺ        let v1: Vec<i32> = v1_float.iter().map(|&x| x.round() as i32).collect();
520Ôćĺ
521Ôćĺ        // s = (point, 0) - v
522Ôćĺ        // s0 = point - v0, s1 = -v1
523Ôćĺ        let s0: Vec<i32> = point.iter().zip(v0.iter()).map(|(&p, &v)| p - v).collect();
524Ôćĺ        let s1: Vec<i32> = v1.iter().map(|&v| -v).collect();
525Ôćĺ
526Ôćĺ        (s0, s1)
527Ôćĺ    }
528Ôćĺ
529Ôćĺ    /// Verify a signature.
530Ôćĺ    ///
531Ôćĺ    /// Checks that a signature is valid for the given message and verifying key.
532Ôćĺ    ///
533Ôćĺ    /// # Arguments
534Ôćĺ    ///
535Ôćĺ    /// * `vk` - The verifying key (public key)
536Ôćĺ    /// * `message` - The message that was supposedly signed
537Ôćĺ    /// * `sig` - The signature to verify
538Ôćĺ    ///
539Ôćĺ    /// # Returns
540Ôćĺ    ///
541Ôćĺ    /// - `Ok(true)` if the signature is valid
542Ôćĺ    /// - `Ok(false)` if the signature is mathematically invalid (wrong key or message)
543Ôćĺ    /// - `Err(FalconError)` if the signature is malformed
544Ôćĺ    pub fn verify(vk: &VerifyingKey, message: &[u8], sig: &Signature) -> Result<bool, FalconError>
545Ôćĺ    where
546Ôćĺ        H: HashToPoint<Input = u8>,
547Ôćĺ    {
548Ôćĺ        // Decompress s1
549Ôćĺ        let s1 = decompress(&sig.s1_enc, N).ok_or(FalconError::DecompressionFailed)?;
550Ôćĺ
551Ôćĺ        // Hash the message
552Ôćĺ        let hashed = H::hash_to_point(message, &sig.salt);
553Ôćĺ        let hashed_i32: Vec<i32> = hashed.iter().map(|&x| x as i32).collect();
554Ôćĺ
555Ôćĺ        // Compute s0 = hashed - s1 * h
556Ôćĺ        let h_vec: Vec<i32> = vk.h.iter().copied().collect();
557Ôćĺ        let s1_h = mul_zq(&s1, &h_vec);
558Ôćĺ        let s0 = sub_zq(&hashed_i32, &s1_h);
559Ôćĺ
560Ôćĺ        // Normalize s0 coefficients to (-q/2, q/2]
561Ôćĺ        let s0_centered: Vec<i32> = s0
562Ôćĺ            .iter()
563Ôćĺ            .map(|&c| {
564Ôćĺ                let c = c.rem_euclid(Q);
565Ôćĺ                if c > Q / 2 {
566Ôćĺ                    c - Q
567Ôćĺ                } else {
568Ôćĺ                    c
569Ôćĺ                }
570Ôćĺ            })
571Ôćĺ            .collect();
572Ôćĺ
573Ôćĺ        // Check signature norm
574Ôćĺ        let s0_slice: &[i32] = &s0_centered;
575Ôćĺ        let s1_slice: &[i32] = &s1;
576Ôćĺ        let norm = sqnorm(&[s0_slice, s1_slice]);
577Ôćĺ
578Ôćĺ        if norm > SIG_BOUND {
579Ôćĺ            return Ok(false);
580Ôćĺ        }
581Ôćĺ
582Ôćĺ        Ok(true)
583Ôćĺ    }
584Ôćĺ}
