 1Ôćĺ//! Hint generation for Falcon verification.
 2Ôćĺ//!
 3Ôćĺ//! Generates the mul_hint = INTT(NTT(s1) * pk_h_ntt) that allows
 4Ôćĺ//! Cairo to verify NTT products without computing INTT on-chain.
 5Ôćĺ
 6Ôćĺuse crate::ntt::{ntt, intt, mul_ntt};
 7Ôćĺuse crate::Q;
 8Ôćĺ
 9Ôćĺ/// Generate INTT(NTT(s1) * pk_h_ntt) ÔÇö the mul_hint for verification.
10Ôćĺpub fn generate_mul_hint(s1: &[u16], pk_h_ntt: &[u16]) -> Vec<u16> {
11Ôćĺ    let s1_i32: Vec<i32> = s1.iter().map(|&v| v as i32).collect();
12Ôćĺ    let pk_i32: Vec<i32> = pk_h_ntt.iter().map(|&v| v as i32).collect();
13Ôćĺ
14Ôćĺ    let s1_ntt = ntt(&s1_i32);
15Ôćĺ    let product_ntt = mul_ntt(&s1_ntt, &pk_i32);
16Ôćĺ    let product = intt(&product_ntt);
17Ôćĺ
18Ôćĺ    product
19Ôćĺ        .iter()
20Ôćĺ        .map(|&v| v.rem_euclid(Q) as u16)
21Ôćĺ        .collect()
22Ôćĺ}
