32Ôćĺ        s1[0] = 1;
33Ôćĺ        let pk_coeff: Vec<i32> = s1.iter().map(|&v| v as i32).collect();
34Ôćĺ        let pk_ntt = ntt(&pk_coeff);
35Ôćĺ        let pk_u16: Vec<u16> = pk_ntt.iter().map(|&v| v.rem_euclid(Q) as u16).collect();
