  1Ôćĺ//! Hash-to-point trait for customizable hash functions.
  2Ôćĺ//!
  3Ôćĺ//! Falcon requires hashing messages to points in Z_q[X]/(X^n + 1).
  4Ôćĺ//! This module provides the trait and a default SHAKE256 implementation.
  5Ôćĺ
  6Ôćĺuse crate::{N, Q};
  7Ôćĺ
  8Ôćĺ/// Trait for hashing message to polynomial in Z_q[x]/(x^n + 1).
  9Ôćĺ///
 10Ôćĺ/// This trait allows swapping the hash function used in Falcon,
 11Ôćĺ/// enabling use of Poseidon for Starknet compatibility.
 12Ôćĺ///
 13Ôćĺ/// The associated type `Input` determines the element type for message and salt:
 14Ôćĺ/// - `u8` for byte-oriented hashing (SHAKE256)
 15Ôćĺ/// - `Felt` for field-element hashing (Poseidon/Starknet)
 16Ôćĺpub trait HashToPoint {
 17Ôćĺ    /// Element type for message and salt slices.
 18Ôćĺ    type Input;
 19Ôćĺ
 20Ôćĺ    /// Hash a message with salt to a polynomial in Z_q[x].
 21Ôćĺ    fn hash_to_point(message: &[Self::Input], salt: &[Self::Input]) -> [i16; N];
 22Ôćĺ}
 23Ôćĺ
 24Ôćĺ/// SHAKE256-based hash (matches Python reference implementation).
 25Ôćĺ#[cfg(feature = "shake")]
 26Ôćĺpub struct Shake256Hash;
 27Ôćĺ
 28Ôćĺ#[cfg(feature = "shake")]
 29Ôćĺimpl HashToPoint for Shake256Hash {
 30Ôćĺ    type Input = u8;
 31Ôćĺ
 32Ôćĺ    fn hash_to_point(message: &[u8], salt: &[u8]) -> [i16; N] {
 33Ôćĺ        use sha3::{
 34Ôćĺ            digest::{ExtendableOutput, Update, XofReader},
 35Ôćĺ            Shake256,
 36Ôćĺ        };
 37Ôćĺ
 38Ôćĺ        let mut hasher = Shake256::default();
 39Ôćĺ        hasher.update(salt);
 40Ôćĺ        hasher.update(message);
 41Ôćĺ        let mut reader = hasher.finalize_xof();
 42Ôćĺ
 43Ôćĺ        // Rejection sampling parameter: k = floor(2^16 / q)
 44Ôćĺ        let k = (1u32 << 16) / (Q as u32);
 45Ôćĺ        let mut hashed = [0i16; N];
 46Ôćĺ        let mut i = 0;
 47Ôćĺ
 48Ôćĺ        while i < N {
 49Ôćĺ            let mut buf = [0u8; 2];
 50Ôćĺ            reader.read(&mut buf);
 51Ôćĺ            // Big-endian as per Python reference
 52Ôćĺ            let elt = ((buf[0] as u32) << 8) | (buf[1] as u32);
 53Ôćĺ
 54Ôćĺ            // Rejection sampling to ensure uniform distribution
 55Ôćĺ            if elt < k * (Q as u32) {
 56Ôćĺ                hashed[i] = (elt % (Q as u32)) as i16;
 57Ôćĺ                i += 1;
 58Ôćĺ            }
 59Ôćĺ        }
 60Ôćĺ
 61Ôćĺ        hashed
 62Ôćĺ    }
 63Ôćĺ}
