  1Ôćĺ//! Poseidon hash_to_point for Falcon-512 (Starknet-compatible).
  2Ôćĺ//!
  3Ôćĺ//! Uses lambdaworks PoseidonCairoStark252 to match the Cairo implementation.
  4Ôćĺ//! Produces 512 coefficients in [0, Q) from (message, salt) using:
  5Ôćĺ//! - poseidon_hash_span(message || salt) -> single felt252 seed
  6Ôćĺ//! - Squeeze: 22 hades_permutations, base-Q extraction (12 Zq per felt252)
  7Ôćĺ
  8Ôćĺuse crate::hash_to_point::HashToPoint;
  9Ôćĺuse crate::{N, Q};
 10Ôćĺuse lambdaworks_crypto::hash::poseidon::starknet::PoseidonCairoStark252;
 11Ôćĺuse lambdaworks_crypto::hash::poseidon::Poseidon;
 12Ôćĺuse lambdaworks_math::field::element::FieldElement;
 13Ôćĺuse lambdaworks_math::field::fields::fft_friendly::stark_252_prime_field::Stark252PrimeField;
 14Ôćĺ
 15Ôćĺpub type Felt = FieldElement<Stark252PrimeField>;
 16Ôćĺ
 17Ôćĺpub struct PoseidonHashToPoint;
 18Ôćĺ
 19Ôćĺimpl HashToPoint for PoseidonHashToPoint {
 20Ôćĺ    type Input = Felt;
 21Ôćĺ
 22Ôćĺ    /// Hash message and salt (as felt252 arrays) to 512 Zq coefficients.
 23Ôćĺ    /// This matches the Cairo PoseidonHashToPoint implementation exactly.
 24Ôćĺ    fn hash_to_point(message: &[Felt], salt: &[Felt]) -> [i16; N] {
 25Ôćĺ        // Absorb: poseidon_hash_span(message || salt) -> single felt252 seed
 26Ôćĺ        let combined: Vec<Felt> = message.iter().chain(salt.iter()).cloned().collect();
 27Ôćĺ        let seed = PoseidonCairoStark252::hash_many(&combined);
 28Ôćĺ
 29Ôćĺ        // Squeeze: 21 full rounds (504 coefficients) + 1 partial round (8 coefficients)
 30Ôćĺ        let mut state = [seed, Felt::zero(), Felt::zero()];
 31Ôćĺ        let mut coeffs = [0i16; N];
 32Ôćĺ        let mut idx = 0;
 33Ôćĺ
 34Ôćĺ        for _ in 0..21 {
 35Ôćĺ            PoseidonCairoStark252::hades_permutation(&mut state);
 36Ôćĺ            idx += extract_12_from_felt(&state[0], &mut coeffs, idx);
 37Ôćĺ            idx += extract_12_from_felt(&state[1], &mut coeffs, idx);
 38Ôćĺ        }
 39Ôćĺ
 40Ôćĺ        // Final round: only need 8 more from state[0]
 41Ôćĺ        PoseidonCairoStark252::hades_permutation(&mut state);
 42Ôćĺ        extract_12_from_felt(&state[0], &mut coeffs, idx);
 43Ôćĺ        // extract_12 stops at N=512, giving exactly 8 (6 from low + 2 from high)
 44Ôćĺ
 45Ôćĺ        coeffs
 46Ôćĺ    }
 47Ôćĺ}
 48Ôćĺ
 49Ôćĺfn extract_12_from_felt(value: &Felt, out: &mut [i16; N], start: usize) -> usize {
 50Ôćĺ    let bytes = value.to_bytes_be();
 51Ôćĺ    // bytes is 32 bytes big-endian: [0..16] = high u128, [16..32] = low u128
 52Ôćĺ    let high = u128::from_be_bytes(bytes[0..16].try_into().unwrap());
 53Ôćĺ    let low = u128::from_be_bytes(bytes[16..32].try_into().unwrap());
 54Ôćĺ
 55Ôćĺ    let mut count = 0;
 56Ôćĺ    // Extract 6 from low u128 first (matching Cairo's extract_6_from_low)
 57Ôćĺ    count += extract_6_from_u128(low, out, start + count);
 58Ôćĺ    // Extract 6 from high (matching Cairo's extract_6_from_high)
 59Ôćĺ    count += extract_6_from_u128(high, out, start + count);
 60Ôćĺ    count
 61Ôćĺ}
 62Ôćĺ
 63Ôćĺfn extract_6_from_u128(mut value: u128, out: &mut [i16; N], start: usize) -> usize {
 64Ôćĺ    for i in 0..6 {
 65Ôćĺ        if start + i >= N {
 66Ôćĺ            return i;
 67Ôćĺ        }
 68Ôćĺ        out[start + i] = (value % Q as u128) as i16;
 69Ôćĺ        value /= Q as u128;
 70Ôćĺ    }
