  1Ôćĺ//! Base-Q polynomial packing for Falcon public keys.
  2Ôćĺ//!
  3Ôćĺ//! Packs 512 Zq values into 29 felt252 slots using base Q=12289 encoding:
  4Ôćĺ//!   felt252 = horner_pack(v0..v8) + horner_pack(v9..v17) * 2^128
  5Ôćĺ//!
  6Ôćĺ//! Matches the Cairo packing.cairo implementation exactly.
  7Ôćĺ
  8Ôćĺuse crate::poseidon_hash::Felt;
  9Ôćĺuse crate::Q;
 10Ôćĺuse lambdaworks_math::unsigned_integer::element::UnsignedInteger;
 11Ôćĺ
 12Ôćĺconst VALS_PER_U128: usize = 9;
 13Ôćĺconst VALS_PER_FELT: usize = 18;
 14Ôćĺpub const PACKED_SLOTS: usize = 29;
 15Ôćĺ
 16Ôćĺ/// Convert a u128 to Felt
 17Ôćĺfn felt_from_u128(v: u128) -> Felt {
 18Ôćĺ    Felt::from(&UnsignedInteger::from_u128(v))
 19Ôćĺ}
 20Ôćĺ
 21Ôćĺ/// 2^128 as Felt
 22Ôćĺfn two_pow_128() -> Felt {
 23Ôćĺ    Felt::from_hex("0x100000000000000000000000000000000").unwrap()
 24Ôćĺ}
 25Ôćĺ
 26Ôćĺ/// Pack 512 Zq values into 29 Felt values using base-Q Horner encoding.
 27Ôćĺpub fn pack_public_key(h_ntt: &[u16]) -> Vec<Felt> {
 28Ôćĺ    assert_eq!(h_ntt.len(), 512);
 29Ôćĺ    h_ntt
 30Ôćĺ        .chunks(VALS_PER_FELT)
 31Ôćĺ        .map(|chunk| {
 32Ôćĺ            let split = chunk.len().min(VALS_PER_U128);
 33Ôćĺ            let lo = horner_pack(&chunk[..split]);
 34Ôćĺ            let hi = if chunk.len() > split {
 35Ôćĺ                horner_pack(&chunk[split..])
 36Ôćĺ            } else {
 37Ôćĺ                0u128
 38Ôćĺ            };
 39Ôćĺ            felt_from_u128(lo) + felt_from_u128(hi) * two_pow_128()
 40Ôćĺ        })
 41Ôćĺ        .collect()
 42Ôćĺ}
 43Ôćĺ
 44Ôćĺ/// Unpack 29 Felt values back to 512 Zq values.
 45Ôćĺpub fn unpack_public_key(packed: &[Felt]) -> Vec<u16> {
 46Ôćĺ    let mut result = Vec::with_capacity(512);
 47Ôćĺ    let mut remaining = 512usize;
 48Ôćĺ
 49Ôćĺ    for felt in packed {
 50Ôćĺ        let bytes = felt.to_bytes_be();
 51Ôćĺ        let high = u128::from_be_bytes(bytes[0..16].try_into().unwrap());
 52Ôćĺ        let low = u128::from_be_bytes(bytes[16..32].try_into().unwrap());
 53Ôćĺ
 54Ôćĺ        let lo_count = remaining.min(VALS_PER_U128);
 55Ôćĺ        base_q_extract(low, lo_count, &mut result);
 56Ôćĺ        remaining -= lo_count;
 57Ôćĺ
 58Ôćĺ        if remaining > 0 {
 59Ôćĺ            let hi_count = remaining.min(VALS_PER_U128);
 60Ôćĺ            base_q_extract(high, hi_count, &mut result);
 61Ôćĺ            remaining -= hi_count;
 62Ôćĺ        }
 63Ôćĺ    }
 64Ôćĺ    result
 65Ôćĺ}
 66Ôćĺ
 67Ôćĺfn horner_pack(values: &[u16]) -> u128 {
 68Ôćĺ    let mut acc: u128 = 0;
 69Ôćĺ    for &v in values.iter().rev() {
 70Ôćĺ        acc = acc * Q as u128 + v as u128;
 71Ôćĺ    }
 72Ôćĺ    acc
 73Ôćĺ}
 74Ôćĺ
 75Ôćĺfn base_q_extract(mut value: u128, count: usize, out: &mut Vec<u16>) {
 76Ôćĺ    for _ in 0..count {
 77Ôćĺ        out.push((value % Q as u128) as u16);
 78Ôćĺ        value /= Q as u128;
 79Ôćĺ    }
 80Ôćĺ}
 81Ôćĺ
 82Ôćĺ#[cfg(test)]
 83Ôćĺmod tests {
 84Ôćĺ    use super::*;
 85Ôćĺ
 86Ôćĺ    #[test]
 87Ôćĺ    fn test_packing_roundtrip() {
 88Ôćĺ        let mut values = vec![0u16; 512];
 89Ôćĺ        for i in 0..512 {
 90Ôćĺ            values[i] = (i * 37 % 12289) as u16;
 91Ôćĺ        }
 92Ôćĺ        let packed = pack_public_key(&values);
 93Ôćĺ        assert_eq!(packed.len(), PACKED_SLOTS);
 94Ôćĺ        let unpacked = unpack_public_key(&packed);
 95Ôćĺ        assert_eq!(unpacked, values);
 96Ôćĺ    }
 97Ôćĺ
 98Ôćĺ    #[test]
 99Ôćĺ    fn test_packing_edge_cases() {
100Ôćĺ        // All zeros
101Ôćĺ        let zeros = vec![0u16; 512];
102Ôćĺ        assert_eq!(unpack_public_key(&pack_public_key(&zeros)), zeros);
103Ôćĺ
104Ôćĺ        // All max
105Ôćĺ        let maxes = vec![12288u16; 512];
106Ôćĺ        assert_eq!(unpack_public_key(&pack_public_key(&maxes)), maxes);
107Ôćĺ    }
108Ôćĺ}
