  1Ôćĺ//! Number Theoretic Transform over Z_q[x]/(x^n + 1).
  2Ôćĺ
  3Ôćĺuse crate::constants::{ntt_roots, I2, INV_MOD_Q, SQR1};
  4Ôćĺuse crate::Q;
  5Ôćĺ
  6Ôćĺ/// Split a polynomial in NTT representation.
  7Ôćĺpub fn split_ntt(f_ntt: &[i32]) -> (Vec<i32>, Vec<i32>) {
  8Ôćĺ    let n = f_ntt.len();
  9Ôćĺ    let w = ntt_roots(n);
 10Ôćĺ    let mut f0_ntt = vec![0i32; n / 2];
 11Ôćĺ    let mut f1_ntt = vec![0i32; n / 2];
 12Ôćĺ
 13Ôćĺ    for i in 0..n / 2 {
 14Ôćĺ        let sum = (f_ntt[2 * i] + f_ntt[2 * i + 1]).rem_euclid(Q);
 15Ôćĺ        let diff = (f_ntt[2 * i] - f_ntt[2 * i + 1]).rem_euclid(Q);
 16Ôćĺ        f0_ntt[i] = ((I2 as i64 * sum as i64) % Q as i64) as i32;
 17Ôćĺ        f1_ntt[i] =
 18Ôćĺ            ((I2 as i64 * diff as i64 * INV_MOD_Q[w[2 * i] as usize] as i64) % Q as i64) as i32;
 19Ôćĺ    }
 20Ôćĺ    (f0_ntt, f1_ntt)
 21Ôćĺ}
 22Ôćĺ
 23Ôćĺ/// Merge two polynomials in NTT representation.
 24Ôćĺpub fn merge_ntt(f0_ntt: &[i32], f1_ntt: &[i32]) -> Vec<i32> {
 25Ôćĺ    let n = 2 * f0_ntt.len();
 26Ôćĺ    let w = ntt_roots(n);
 27Ôćĺ    let mut f_ntt = vec![0i32; n];
 28Ôćĺ
 29Ôćĺ    for i in 0..n / 2 {
 30Ôćĺ        let wf1 = ((w[2 * i] as i64 * f1_ntt[i] as i64) % Q as i64) as i32;
 31Ôćĺ        f_ntt[2 * i] = (f0_ntt[i] + wf1).rem_euclid(Q);
 32Ôćĺ        f_ntt[2 * i + 1] = (f0_ntt[i] - wf1).rem_euclid(Q);
 33Ôćĺ    }
 34Ôćĺ    f_ntt
 35Ôćĺ}
 36Ôćĺ
 37Ôćĺ/// Compute NTT of a polynomial (coefficient -> NTT representation).
 38Ôćĺpub fn ntt(f: &[i32]) -> Vec<i32> {
 39Ôćĺ    let n = f.len();
 40Ôćĺ    if n > 2 {
 41Ôćĺ        let mut f0 = vec![0i32; n / 2];
 42Ôćĺ        let mut f1 = vec![0i32; n / 2];
 43Ôćĺ        for i in 0..n / 2 {
 44Ôćĺ            f0[i] = f[2 * i];
 45Ôćĺ            f1[i] = f[2 * i + 1];
 46Ôćĺ        }
 47Ôćĺ        let f0_ntt = ntt(&f0);
 48Ôćĺ        let f1_ntt = ntt(&f1);
 49Ôćĺ        merge_ntt(&f0_ntt, &f1_ntt)
 50Ôćĺ    } else {
 51Ôćĺ        let mut f_ntt = vec![0i32; n];
 52Ôćĺ        f_ntt[0] = (f[0] + ((SQR1 as i64 * f[1] as i64) % Q as i64) as i32).rem_euclid(Q);
 53Ôćĺ        f_ntt[1] = (f[0] - ((SQR1 as i64 * f[1] as i64) % Q as i64) as i32).rem_euclid(Q);
 54Ôćĺ        f_ntt
 55Ôćĺ    }
 56Ôćĺ}
 57Ôćĺ
 58Ôćĺ/// Compute inverse NTT (NTT -> coefficient representation).
 59Ôćĺpub fn intt(f_ntt: &[i32]) -> Vec<i32> {
 60Ôćĺ    let n = f_ntt.len();
 61Ôćĺ    if n > 2 {
 62Ôćĺ        let (f0_ntt, f1_ntt) = split_ntt(f_ntt);
 63Ôćĺ        let f0 = intt(&f0_ntt);
 64Ôćĺ        let f1 = intt(&f1_ntt);
 65Ôćĺ        // merge
 66Ôćĺ        let mut f = vec![0i32; n];
 67Ôćĺ        for i in 0..n / 2 {
 68Ôćĺ            f[2 * i] = f0[i];
 69Ôćĺ            f[2 * i + 1] = f1[i];
 70Ôćĺ        }
 71Ôćĺ        f
 72Ôćĺ    } else {
 73Ôćĺ        let mut f = vec![0i32; n];
 74Ôćĺ        let sum = (f_ntt[0] + f_ntt[1]).rem_euclid(Q);
 75Ôćĺ        let diff = (f_ntt[0] - f_ntt[1]).rem_euclid(Q);
 76Ôćĺ        f[0] = ((I2 as i64 * sum as i64) % Q as i64) as i32;
 77Ôćĺ        f[1] = ((I2 as i64 * INV_MOD_Q[SQR1 as usize] as i64 * diff as i64) % Q as i64) as i32;
 78Ôćĺ        f
 79Ôćĺ    }
 80Ôćĺ}
 81Ôćĺ
 82Ôćĺ/// Addition of two polynomials in Z_q.
 83Ôćĺpub fn add_zq(f: &[i32], g: &[i32]) -> Vec<i32> {
 84Ôćĺ    assert_eq!(f.len(), g.len());
 85Ôćĺ    f.iter()
 86Ôćĺ        .zip(g.iter())
 87Ôćĺ        .map(|(&a, &b)| (a + b).rem_euclid(Q))
 88Ôćĺ        .collect()
 89Ôćĺ}
 90Ôćĺ
 91Ôćĺ/// Negation of a polynomial in Z_q.
 92Ôćĺpub fn neg_zq(f: &[i32]) -> Vec<i32> {
 93Ôćĺ    f.iter().map(|&a| (-a).rem_euclid(Q)).collect()
 94Ôćĺ}
 95Ôćĺ
 96Ôćĺ/// Subtraction of two polynomials in Z_q.
 97Ôćĺpub fn sub_zq(f: &[i32], g: &[i32]) -> Vec<i32> {
 98Ôćĺ    add_zq(f, &neg_zq(g))
 99Ôćĺ}
100Ôćĺ
101Ôćĺ/// Multiplication in NTT representation (pointwise).
102Ôćĺpub fn mul_ntt(f_ntt: &[i32], g_ntt: &[i32]) -> Vec<i32> {
103Ôćĺ    assert_eq!(f_ntt.len(), g_ntt.len());
104Ôćĺ    f_ntt
105Ôćĺ        .iter()
106Ôćĺ        .zip(g_ntt.iter())
107Ôćĺ        .map(|(&a, &b)| ((a as i64 * b as i64) % Q as i64) as i32)
108Ôćĺ        .collect()
109Ôćĺ}
110Ôćĺ
111Ôćĺ/// Division in NTT representation (pointwise).
112Ôćĺpub fn div_ntt(f_ntt: &[i32], g_ntt: &[i32]) -> Option<Vec<i32>> {
113Ôćĺ    assert_eq!(f_ntt.len(), g_ntt.len());
114Ôćĺ    if g_ntt.iter().any(|&x| x == 0) {
115Ôćĺ        return None;
116Ôćĺ    }
117Ôćĺ    Some(
118Ôćĺ        f_ntt
119Ôćĺ            .iter()
120Ôćĺ            .zip(g_ntt.iter())
121Ôćĺ            .map(|(&a, &b)| ((a as i64 * INV_MOD_Q[b as usize] as i64) % Q as i64) as i32)
122Ôćĺ            .collect(),
123Ôćĺ    )
124Ôćĺ}
125Ôćĺ
126Ôćĺ/// Multiplication of two polynomials in coefficient representation.
127Ôćĺpub fn mul_zq(f: &[i32], g: &[i32]) -> Vec<i32> {
128Ôćĺ    intt(&mul_ntt(&ntt(f), &ntt(g)))
129Ôćĺ}
130Ôćĺ
131Ôćĺ/// Division of two polynomials in coefficient representation.
132Ôćĺpub fn div_zq(f: &[i32], g: &[i32]) -> Option<Vec<i32>> {
133Ôćĺ    div_ntt(&ntt(f), &ntt(g)).map(|r| intt(&r))
134Ôćĺ}
135Ôćĺ
