 1Ôćĺ//! Serialization utilities for generating snforge-compatible JSON test data.
 2Ôćĺ//!
 3Ôćĺ//! Produces JSON in the format expected by Cairo's `read_json` + `Serde::deserialize`.
 4Ôćĺ//! Values must be JSON integers (not strings) for snforge to parse correctly.
 5Ôćĺ
 6Ôćĺuse crate::poseidon_hash::Felt;
 7Ôćĺuse num_bigint::BigUint;
 8Ôćĺuse serde_json::{json, Number, Value};
 9Ôćĺ
10Ôćĺ/// Serialize an array of u16 values as Cairo Serde: [length, v0, v1, ...]
11Ôćĺfn serde_u16_array(values: &[u16]) -> Vec<Value> {
12Ôćĺ    let mut out = Vec::with_capacity(values.len() + 1);
13Ôćĺ    out.push(Value::Number(Number::from(values.len())));
14Ôćĺ    for &v in values {
15Ôćĺ        out.push(Value::Number(Number::from(v)));
16Ôćĺ    }
17Ôćĺ    out
18Ôćĺ}
19Ôćĺ
20Ôćĺ/// Serialize an array of Felt values as Cairo Serde: [length, f0, f1, ...]
21Ôćĺ/// Felt values that fit in u64 are serialized as JSON numbers.
22Ôćĺ/// Larger values are serialized as decimal strings (snforge handles both).
23Ôćĺfn serde_felt_array(values: &[Felt]) -> Vec<Value> {
24Ôćĺ    let mut out = Vec::with_capacity(values.len() + 1);
25Ôćĺ    out.push(Value::Number(Number::from(values.len())));
26Ôćĺ    for v in values {
27Ôćĺ        out.push(felt_to_json_value(v));
28Ôćĺ    }
29Ôćĺ    out
30Ôćĺ}
31Ôćĺ
32Ôćĺfn felt_to_json_value(f: &Felt) -> Value {
33Ôćĺ    let bytes = f.to_bytes_be();
34Ôćĺ    let num = BigUint::from_bytes_be(&bytes);
35Ôćĺ    let decimal = num.to_string();
36Ôćĺ    // Use arbitrary_precision to emit large numbers as JSON integers (not strings)
37Ôćĺ    Value::Number(Number::from_string_unchecked(decimal))
38Ôćĺ}
39Ôćĺ
40Ôćĺ/// Generate snforge-compatible JSON for hash_to_point test data.
41Ôćĺpub fn hash_to_point_test_json(
42Ôćĺ    message: &[Felt],
43Ôćĺ    salt: &[Felt],
44Ôćĺ    expected: &[u16],
45Ôćĺ) -> Value {
46Ôćĺ    let mut payload = Vec::new();
47Ôćĺ    payload.extend(serde_felt_array(message));
48Ôćĺ    payload.extend(serde_felt_array(salt));
49Ôćĺ    payload.extend(serde_u16_array(expected));
50Ôćĺ    json!({ "hash_to_point_test": payload })
51Ôćĺ}
52Ôćĺ
53Ôćĺ/// Generate snforge-compatible JSON for packing test data.
54Ôćĺpub fn packing_test_json(values: &[u16], packed: &[Felt]) -> Value {
55Ôćĺ    let mut payload = Vec::new();
56Ôćĺ    payload.extend(serde_u16_array(values));
57Ôćĺ    payload.extend(serde_felt_array(packed));
58Ôćĺ    json!({ "packing_test": payload })
59Ôćĺ}
60Ôćĺ
61Ôćĺ/// Generate snforge-compatible JSON for end-to-end verify test data.
62Ôćĺpub fn verify_test_json(
63Ôćĺ    message: &[Felt],
64Ôćĺ    salt: &[Felt],
65Ôćĺ    pk_ntt: &[u16],
66Ôćĺ    s1: &[u16],
67Ôćĺ    mul_hint: &[u16],
68Ôćĺ) -> Value {
69Ôćĺ    let mut payload = Vec::new();
70Ôćĺ    payload.extend(serde_felt_array(message));
71Ôćĺ    payload.extend(serde_felt_array(salt));
72Ôćĺ    payload.extend(serde_u16_array(pk_ntt));
