        let message = b"Hello, Falcon!";
        let salt = [0u8; SALT_LEN];
        let sig = Falcon::<Shake256Hash>::sign_with_salt(&sk, message, &salt);

        let result = Falcon::<Shake256Hash>::verify(&vk, message, &sig);
