				reviewChecklist={[
					"Spec compliance ÔÇö does implementation match the spec?",
					"Test coverage ÔÇö every public API has tests",
					"Security ÔÇö no injection, no leaked secrets",
				]}
				maxConcurrency={WORKFLOW_MAX_CONCURRENCY}
				taskRetries={WORKFLOW_TASK_RETRIES}
				skipPhases={skipPhases}

#!/usr/bin/env bun

/**
 * {{PROJECT_NAME}} ÔÇö super-ralph run manager
 *
 * Usage:
 *   bun run index.ts                              ÔÇö interactive run picker
 *   SKIPTO_PHASE=TICKETS bun run index.ts         ÔÇö skip to ticket work
 *   WORKFLOW_MAX_CONCURRENCY=4 bun run index.ts   ÔÇö tune concurrency
 *
 * Phases: PROGRESS Ôćĺ CODEBASE_REVIEW Ôćĺ DISCOVER Ôćĺ TICKETS Ôćĺ INTEGRATION_TEST
 */

import { existsSync } from "node:fs";
import { createInterface } from "node:readline";
import { dirname, join, resolve } from "node:path";
import { fileURLToPath } from "node:url";
